function format(value: string | number | boolean | null): string {
  if (value === null)          return "(empty)";
  switch (typeof value) {
    case "string":  return `"${value}"`;
    case "number":  return value.toFixed(2);
    case "boolean": return value ? "yes" : "no";
    default: return String(value);
  }
}

const values = ["hello", 42, 3.14, true, false, null];
for (const v of values) console.log(format(v));

class NetworkError extends Error {
  constructor(message: string, public statusCode: number) {
    super(message); this.name = "NetworkError";
  }
}
class ValidationError extends Error {
  constructor(message: string, public field: string) {
    super(message); this.name = "ValidationError";
  }
}

function handle(err: unknown): string {
  if (err instanceof ValidationError) return `Validation on '${err.field}': ${err.message}`;
  if (err instanceof NetworkError) return `HTTP ${err.statusCode}: ${err.message}`;
  if (err instanceof Error) return `Error: ${err.message}`;
  return `Unknown: ${String(err)}`;
}

console.log(handle(new ValidationError("Required", "email")));
console.log(handle(new NetworkError("Not found", 404)));
console.log(handle(new Error("Generic")));

interface TextResponse  { type: "text";  text: string }
interface ImageResponse { type: "image"; url: string; alt: string }
interface DataResponse  { type: "data";  payload: unknown; count: number }

type ApiResponse = TextResponse | ImageResponse | DataResponse;

function render(r: ApiResponse): string {
  if ("text"  in r && r.type === "text")  return `Text: ${r.text}`;
  if ("url"   in r && r.type === "image") return `Image: ${r.url}`;
  if ("count" in r && r.type === "data")  return `Data: ${r.count} items`;
  return "Unknown";
}

console.log(render({ type: "text",  text: "Hello world" }));
console.log(render({ type: "image", url: "/img.png", alt: "Photo" }));
console.log(render({ type: "data",  payload: [], count: 42 }));

interface User { id: number; name: string; email: string }
interface Product { id: number; name: string; price: number }

function isUser(obj: unknown): obj is User {
  return typeof obj === "object" && obj !== null
    && "email" in obj && typeof (obj as User).email === "string";
}

function isProduct(obj: unknown): obj is Product {
  return typeof obj === "object" && obj !== null
    && "price" in obj && typeof (obj as Product).price === "number";
}

const apiResponses: unknown[] = [
  { id: 1, name: "Alice", email: "alice@co.com" },
  { id: 2, name: "Keyboard", price: 129 },
  { id: 3, name: "Bob", email: "bob@co.com" },
];

for (const r of apiResponses) {
  if (isUser(r))    console.log(`User: ${r.name} <${r.email}>`);
  else if (isProduct(r)) console.log(`Product: ${r.name} $${r.price}`);
}

function assert(condition: boolean, message: string): asserts condition {
  if (!condition) throw new Error(message);
}

function assertString(value: unknown): asserts value is string {
  if (typeof value !== "string") throw new Error(`Expected string, got ${typeof value}`);
}

function processInput(raw: unknown): string {
  assertString(raw);
  // After assertion, TypeScript knows raw is string
  assert(raw.length > 0, "Input cannot be empty");
  assert(raw.length < 100, "Input too long");
  return raw.trim().toLowerCase();
}

const tests = ["  Hello World  ", 42, ""];
for (const t of tests) {
  try {
    console.log(`"${processInput(t)}"`);
  } catch (e) {
    console.log(`Error: ${(e as Error).message}`);
  }
}

type PaymentMethod =
  | { kind: "card";   last4: string; brand: string }
  | { kind: "paypal"; email: string }
  | { kind: "bank";   accountLast4: string; bankName: string };

function describePayment(pm: PaymentMethod): string {
  switch (pm.kind) {
    case "card":   return `${pm.brand} card ending in ${pm.last4}`;
    case "paypal": return `PayPal (${pm.email})`;
    case "bank":   return `${pm.bankName} account ***${pm.accountLast4}`;
  }
}

