  { kind: "paypal", email: "alice@example.com" },
  { kind: "bank",   accountLast4: "6789", bankName: "Chase" },
];

for (const m of methods) console.log(describePayment(m));

interface Config {
  database: { host: string; port: number } | null;
  cache: { host: string; ttl: number } | undefined;
  debug: boolean | null;
}

function validateConfig(cfg: Config): string[] {
  const issues: string[] = [];

  if (cfg.database === null) {
    issues.push("Database config is required");
  } else {
    // TypeScript knows database is not null here
    if (cfg.database.port < 1 || cfg.database.port > 65535)
      issues.push("Invalid database port");
  }

  if (cfg.debug === null || cfg.debug === undefined)
    issues.push("Debug setting is required");

  return issues;
}

console.log(validateConfig({ database: null, cache: undefined, debug: true }));
console.log(validateConfig({ database: { host: "localhost", port: 5432 }, cache: undefined, debug: false }));

function processScore(score: number | null): string {
  if (score === null) {
    return "No score";
    // TypeScript knows anything after return is unreachable
  }

  // Here: score is definitely number (not null)
  if (score < 0 || score > 100) {
    return `Invalid score: ${score}`;
  }

  // Here: score is 0-100
  if (score >= 90) return "A";
  if (score >= 80) return "B";
  if (score >= 70) return "C";
  if (score >= 60) return "D";
  return "F";
}

const scores = [95, 83, 72, 58, null, -1, 100];
for (const s of scores) console.log(`${s} → ${processScore(s)}`);

function normalizeIds(input: number | number[]): number[] {
  if (Array.isArray(input)) {
    // TypeScript knows: input is number[]
    return input;
  }
  // TypeScript knows: input is number
  return [input];
}

function processItems(ids: number | number[]): void {
  const normalized = normalizeIds(ids);
  console.log(`Processing ${normalized.length} item(s): ${normalized.join(", ")}`);
}

processItems(42);
processItems([1, 2, 3, 4, 5]);
processItems([100]);

type TaskStatus = "todo" | "in-progress" | "done" | "cancelled";

function getStatusEmoji(status: TaskStatus): string {
  switch (status) {
    case "todo":        return "📋";
    case "in-progress": return "⚙️";
    case "done":        return "✅";
    case "cancelled":   return "❌";
    default: {
      const exhaustive: never = status;
      throw new Error(`Unhandled status: ${exhaustive}`);
    }
  }
}

const statuses: TaskStatus[] = ["todo", "in-progress", "done", "cancelled"];
for (const s of statuses) {
  console.log(`${getStatusEmoji(s)} ${s}`);
}

type Animal =
  | { kind: "dog"; name: string; breed: string }
  | { kind: "cat"; name: string; indoor: boolean }
  | { kind: "bird"; name: string; canFly: boolean };

const animals: Animal[] = [
  { kind: "dog",  name: "Rex",    breed: "Labrador" },
  { kind: "cat",  name: "Whiskers", indoor: true   },
  { kind: "bird", name: "Tweety",  canFly: true    },
  { kind: "dog",  name: "Buddy",  breed: "Beagle"  },
  { kind: "cat",  name: "Luna",   indoor: false    },
];

// Type predicate in filter gives typed result
const dogs = animals.filter((a): a is Extract<Animal, { kind: "dog" }> => a.kind === "dog");
const cats = animals.filter((a): a is Extract<Animal, { kind: "cat" }> => a.kind === "cat");

console.log(`Dogs: ${dogs.map(d => `${d.name} (${d.breed})`).join(", ")}`);
console.log(`Indoor cats: ${cats.filter(c => c.indoor).map(c => c.name).join(", ")}`);

interface UserProfile {
  id: number;
  name: string;
  bio?: string;
  website?: string;
  twitterHandle?: string;
}

function buildProfileLinks(user: UserProfile): string[] {
  const links: string[] = [];

  if (user.website) {
    // website is definitely string (not undefined)
    links.push(`Web: ${user.website}`);
  }

  if (user.twitterHandle) {
    links.push(`Twitter: @${user.twitterHandle}`);
  }

  if (!user.bio) {
    links.push("(no bio)");
  } else {
    links.push(`Bio: ${user.bio.slice(0, 30)}...`);
  }

  return links;
}

const alice = buildProfileLinks({
  id: 1, name: "Alice",
  website: "https://alice.dev",
  twitterHandle: "alice_dev",
  bio: "Senior TypeScript developer who loves open source",
});
const bob = buildProfileLinks({ id: 2, name: "Bob" });

console.log(alice.join(" | "));
console.log(bob.join(" | "));

type Color = string;
type FontSize = "sm" | "md" | "lg" | "xl";

interface ThemeConfig {
  colors: Record<string, Color>;
  fontSizes: Record<string, FontSize>;
}

const theme = {
  colors: {
    primary:   "#6366f1",
    secondary: "#10b981",
    danger:    "#ef4444",
  },
  fontSizes: {
    body:    "md" as FontSize,
    heading: "xl" as FontSize,
    small:   "sm" as FontSize,
  },
} satisfies ThemeConfig;

// TypeScript knows exact types — no widening
console.log(`Primary: ${theme.colors.primary}`);
console.log(`Body font: ${theme.fontSizes.body}`);
console.log(`Heading: ${theme.fontSizes.heading}`);
